@module timing  src=timing.lua  loc=330  sha=d013d39  mode=namespace  self=timing

# Invariants & contracts
  @invariant  pure module — no module-level state; all functions take operands explicitly  @ 4
  @invariant  two frames: ppqL (logical) and raw ppq (realisation); forward only — ppq = fromLogical(ppqL) + delayToPPQ(delay), endppq = fromLogical(endppqL); see docs/timing.md  @ 5
  @invariant  atoms are pure (u, shift) functions on the unit interval; inverse via Newton (closed form for id)  @ 6
  @invariant  tile period unit is QN (quarter notes); period may be scalar or {num,den}  @ 7
  @invariant  factor order is inner-to-outer: applyFactors walks forward, unapplyFactors walks backward  @ 8
  @invariant  K is the max stretch factor; bounded atoms have posRange/negRange = max |s| (per sign) keeping slope ∈ [1/K, K]  @ 9

# Shapes
  @shape  Atom = { forward = fn(u, shift) -> v, inverse = fn(v, shift) -> u }  @ 10
  @shape  Factor = { atom = string, shift = number_qn, period = number|{num,den}, phase? = number_qn|{num,den} }  @ 11
  @shape  Composite = { phase? = number_qn|{num,den}, factors = Factor[] }   -- bare {} or {factors={}} both denote identity  @ 12
  @shape  ResolvedFactor = { atom = string, shift = number_unit, T = number_ppq, phase? = number_ppq }  @ 13
  @shape  Shape = { factors, a, b, ya, yb, length, identity? }   -- linear ramps on [0,a] and [b,length]; analytic middle on (a,b)  @ 14
  @shape  AtomMeta = { posRange = number, negRange = number, pulsesPerCycle = 1|2 }  @ 15

